(window.webpackJsonp=window.webpackJsonp||[]).push([[155],{782:function(n,r){n.exports="\x3c!-- \r\ntitle: 01-Python基础\r\nsort: \r\n--\x3e \r\n## python学习阶段常用命令\r\n\r\n- `dir()`\r\n\r\n  > 返回属性列表\r\n  >\r\n  > 可用于查看一个对象的所有方法\r\n\r\n- `type()`\r\n\r\n  > 返回对象类型\r\n  \r\n- `help()`\r\n\r\n  > 返回对象帮助\r\n\r\n- `id()`\r\n\r\n  > 返回对象内存地址\r\n\r\n## 数据类型\r\n\r\n### `list`\t列表\r\n\r\n> list.append()\t\t追加元素\r\n>\r\n> list.insert()\t\t\t插入元素至指定位置\r\n>\r\n> list.pop\t\t\t\t\t删除末尾元素\r\n\r\n### `tuple`\t元组\r\n\r\n> tuple = ( )\t\t\t\t使用（）\t\r\n>\r\n> tuple = ( 1 , )\t\t\t定义一个数据必须加括号\r\n>\r\n> t = ('a', 'b', [\"a\"])\t\t定义一个”可变“tuple\r\n\r\n### `dict`\t字典\r\n\r\n> d = {'a': 5, 'b': 6}\t\t定义一个字典\r\n>\r\n> d = dict([('a', 1), ('b', 2)])\t\r\n>\r\n> d.get('x', val)\t\t\tx不存在的返回值\t\r\n>\r\n> 不准许放入列表\t\r\n\r\n\r\n\r\n## 函数\r\n\r\n### 传参\r\n\r\n> `function(a, b, *change )`\t\r\n>\r\n> 传入可变参数（即不需要名称的参数），所有参数放入一个名叫change的tuple。\r\n>\r\n> `function(a, b, **change )`\t\r\n>\r\n> 传入关键字参数（即带名称的参数），所有参数放入一个名为change的dict中。\r\n>\r\n> `function(a, *, bit)`\t\t\t\t\t\r\n>\r\n> 传入命名关键字参数，必须传入，参数名必须为bit\t例：「bit = \"233\"」\r\n>\r\n> `function(a, b, *args, bit, cat)`\t\r\n>\r\n> 假如有可变参数，就不用加\\*了\r\n>\r\n> `funcation(12, 34, bit, cat=2`)\t可以有缺省值，有默认值也可不传入\t\r\n\r\n### 参数组合\r\n\r\n- ```python\r\n  def f1(a, b, c = 1, *args, **kw):\r\n  ```\r\n\r\n  > ```python\r\n  > f1(1,2,5,'ai','py',dict = hh)\r\n  > >>> a = 1, b = 2, c = 5, args = ('ai','py'), kw = {dict:'hh'}\r\n  > \r\n  > args = (1, 2, 3, 4)\r\n  > kw = {'d': 99, 'x': '#'}\r\n  > f1(*args, **kw)\r\n  > >>> a = 1, b = 2, c = 3, args = (4,) kw = {'d': 99, 'x': '#'} \r\n  > ```\r\n\r\n  \r\n  "}}]);